var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`그렇군요. 분발하겠다고 무작정 노력했지만, 역시 부족했던 거네요.`,JPN:`やっぱり……粉骨砕身頑張ったつもりでしたけど、届かなかったみたいですね。`,ENG:`I get it. I tried my best, but that wasn't good enough, was it?`,TWN:`原來如此。雖然我說自己會奮發向上，拚命努力了，但實力果然還是不夠啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`그간의 배려에 감사했습니다.`,JPN:`今まで、お世話になりました。`,ENG:`Thank you for everything so far.`,TWN:`感謝您這段時間的照顧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`......네? 해고통보를 하려고 부른 게 아니셨나요?`,JPN:`……はい？解雇通告をしに呼び出したんじゃなかったんですか？`,ENG:`Pardon? You didn't call me to fire me?`,TWN:`……什麼？不是為了開我除才叫我的嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`조, 종신계약이라니!!`,JPN:`しゅっ、終身契約ですか！！`,ENG:`A-a lifetime contract?!`,TWN:`居、居然是終身契約！！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`사장님께 인정을 받게 되어서 정말 영광입니다.`,JPN:`社長に認めていただけて、本当に光栄です。`,ENG:`I can't say how happy I am to have your recognition.`,TWN:`得到老闆的認可，我真的感到非常榮幸。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YANGHANSOL_ZODIAC_NULL_NULL`,text:{KOREA:`물론 할 수 있고 말고요! 아직 많이 부족하지만, 결코 사장님을 실망시키지 않겠습니다!`,JPN:`もちろん、やれますとも！
まだまだ若輩者ですけど、決して社長を失望させたりはしません！`,ENG:`I'll sign it, of course! I still have many things to learn, but I swear I'll never disappoint you!`,TWN:`當然沒問題！雖然還有很多不足的地方，但我絕對不會讓老闆您失望！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YANGHANSOL_ZODIAC_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};